    @pytest.mark.django_db
    def test_potential_attrs_for_trial(self, patient_info):
        trial1 = TrialFactory(gender='M', age_low_limit=5, kappa_lambda_abnormal_required=True, bmi_min=27)
        trial2 = TrialFactory(gender='F', systolic_blood_pressure_min=5)

        counts = BlankAttributeRecordsCount().counts(patient_info=patient_info)
        res = UserToTrialAttrsMapper().potential_attrs_for_trial(trial=trial1, counts=counts)
        # print("\n\n>>>>res", res)
        assert res == [{'trialAttributeName': 'gender', 'userAttributeName': 'gender', 'userAttributeTitle': 'Gender', 'count': 2}, {'trialAttributeName': 'ageMin', 'userAttributeName': 'patientAge', 'userAttributeTitle': 'Patient Age', 'count': 1}, {'trialAttributeName': 'bmiMin', 'userAttributeName': 'weight', 'userAttributeTitle': 'Weight', 'count': 1}, {'trialAttributeName': 'bmiMin', 'userAttributeName': 'height', 'userAttributeTitle': 'Height', 'count': 1}, {'trialAttributeName': 'kappaLambdaAbnormalRequired', 'userAttributeName': 'kappaFLC', 'userAttributeTitle': 'Kappa Flc', 'count': 1}, {'trialAttributeName': 'kappaLambdaAbnormalRequired', 'userAttributeName': 'lambdaFLC', 'userAttributeTitle': 'Lambda Flc', 'count': 1}]

